import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"气","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/5.能量池/气.md","filePath":"4.资源分区/5.能量池/气.md"}'),d={name:"4.资源分区/5.能量池/气.md"};function p(l,a,i,_,b,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"气",tabindex:"-1"},[s("气 "),e("a",{class:"header-anchor",href:"#气","aria-label":'Permalink to "气"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘004B")])])],-1),o('<h1 id="气-1" tabindex="-1">气 <a class="header-anchor" href="#气-1" aria-label="Permalink to &quot;气&quot;">​</a></h1><p>气<br> 气是存在于生物之间的根本能量，其性质会随使用者而出现变化，可能偏向暴烈，也可能偏向阴和。</p><p>关键属性：沉着+耐力</p><p>恢复方式：气可以通过一次完整的长休息恢复至能量池上限。也可以在短休息时进行一次能量关键属性的检定，恢复成功数点气。</p><p>气的感知<br> D+500<br> 你开启气能量池<br> 你现在获得一种基于气对事物进行感知的能力。<br> 只要你气能量池不空，你就能在敏感范围内对生物进行模糊定位，这是一种非线性感知方式，同时具有D级别、特异本质的侦测等级。<br> 气的基本用法：你可以支付2点气，令你在洞察检定中获得3dp能量加值，持续一轮。</p><p>气的精进<br> C+1000<br> 前提：气的感知<br> 现在你通过气的感知方式可进行精确定位，如同具有【透视】效果一般，气感知方式的侦测等级提升至C级。<br> 气的基本用法得到了提升：你可以支付6点气，令你在一轮内的洞察检定与防御上获得6点能量加值。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const m=r(d,[["render",p]]);export{f as __pageData,m as default};
